import os
import cv2
import numpy as np
from flask import Flask, request, jsonify
from sklearn.preprocessing import LabelEncoder
from sklearn.svm import SVC
from sklearn.metrics.pairwise import cosine_similarity
from sklearn.preprocessing import normalize
from sklearn.model_selection import train_test_split
from sklearn.decomposition import PCA
from sklearn.pipeline import make_pipeline
from sklearn.preprocessing import StandardScaler

app = Flask(__name__)

# Load and preprocess images
def load_images_from_folder(folder):
    images = []
    labels = []
    for filename in os.listdir(folder):
        img = cv2.imread(os.path.join(folder, filename))
        if img is not None:
            img = cv2.resize(img, (160, 160))
            images.append(img)
            labels.append(filename.split("_")[0])  # Assuming filename format: "name_id.jpg"
    return np.array(images), np.array(labels)

# Feature extraction using PCA
def extract_features(images):
    images_flat = images.reshape(images.shape[0], -1)
    pca = make_pipeline(StandardScaler(), PCA(n_components=100))
    features = pca.fit_transform(images_flat)
    return features, pca

# Train model
def train_model(features, labels):
    le = LabelEncoder()
    labels_encoded = le.fit_transform(labels)
    model = SVC(kernel='linear', probability=True)
    model.fit(features, labels_encoded)
    return model, le

# Load images and train model
images, labels = load_images_from_folder('employee_photos')
features, pca = extract_features(images)
model, le = train_model(features, labels)

# API endpoint for facial recognition
@app.route('/recognize', methods=['POST'])
def recognize():
    file = request.files['image']
    img = cv2.imdecode(np.frombuffer(file.read(), np.uint8), cv2.IMREAD_COLOR)
    img = cv2.resize(img, (160, 160))
    img_flat = img.reshape(1, -1)
    img_features = pca.transform(img_flat)
    
    probabilities = model.predict_proba(img_features)[0]
    probabilities = normalize(probabilities.reshape(1, -1), norm='l1')[0]  # Normalize to sum to 1
    class_indices = np.argsort(probabilities)[::-1]
    response = {
        "predictions": [
            {"label": le.inverse_transform([i])[0], "confidence": float(probabilities[i])}
            for i in class_indices
        ]
    }
    return jsonify(response)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)